const input = $input.first().json;

const requiredText = (fieldName) => {
  const value = String(input[fieldName] ?? '').trim();
  if (!value) {
    throw new Error(`${fieldName} is required`);
  }
  return value;
};

const optionalText = (fieldName) => {
  const value = String(input[fieldName] ?? '').trim();
  return value || undefined;
};

const allowedActions = new Set(['show_control_state', 'pause', 'resume', 'force_stop']);
const action = requiredText('action');
if (!allowedActions.has(action)) {
  throw new Error(`action must be one of: ${Array.from(allowedActions).join(', ')}`);
}

const baseUrl = requiredText('base_url').replace(/\/$/, '');
const runId = requiredText('run_id');
const encodedRunId = encodeURIComponent(runId);
const note = optionalText('note');
const operator = optionalText('operator');
const resumeMode = optionalText('resume_mode') || 'normal';

const commonBody = {};
if (note !== undefined) {
  commonBody.note = note;
}
if (operator !== undefined) {
  commonBody.operator = operator;
}

return [
  {
    json: {
      action,
      run_id: runId,
      inspect_url: `${baseUrl}/v1/runs/${encodedRunId}/control-state`,
      pause_url: `${baseUrl}/v1/runs/${encodedRunId}/pause`,
      resume_url: `${baseUrl}/v1/runs/${encodedRunId}/resume`,
      force_stop_url: `${baseUrl}/v1/runs/${encodedRunId}/force-stop`,
      pause_body: { ...commonBody },
      resume_body: { ...commonBody, mode: resumeMode },
      force_stop_body: { ...commonBody },
    },
  },
];

const response = $input.first().json;
const controlState = response.data?.control_state ?? {};

return [
  {
    json: {
      action: 'show_control_state',
      ok: response.ok,
      request_id: response.request_id,
      run_id: controlState.run_id ?? null,
      run_status: controlState.run_status ?? null,
      queue_status: controlState.queue_status ?? null,
      paused: controlState.paused ?? null,
      terminal: controlState.terminal ?? null,
      scheduling_eligible: controlState.scheduling_eligible ?? null,
      active_step_run_id: controlState.active_step_run_id ?? null,
      latest_manual_transition_type: controlState.latest_manual_transition_type ?? null,
      latest_resume_mode: controlState.latest_resume_mode ?? null,
      raw_response: response,
    },
  },
];

const response = $input.first().json;
const manualControl = response.data?.manual_control ?? {};
const controlState = manualControl.control_state ?? {};
const run = manualControl.run?.run ?? {};

return [
  {
    json: {
      action: 'pause',
      ok: response.ok,
      request_id: response.request_id,
      operation: manualControl.operation ?? null,
      run_id: run.id ?? controlState.run_id ?? null,
      run_status: run.status ?? controlState.run_status ?? null,
      queue_status: controlState.queue_status ?? null,
      paused: controlState.paused ?? null,
      terminal: controlState.terminal ?? null,
      latest_manual_transition_type: controlState.latest_manual_transition_type ?? null,
      latest_resume_mode: controlState.latest_resume_mode ?? null,
      raw_response: response,
    },
  },
];

const response = $input.first().json;
const manualControl = response.data?.manual_control ?? {};
const controlState = manualControl.control_state ?? {};
const run = manualControl.run?.run ?? {};

return [
  {
    json: {
      action: 'resume',
      ok: response.ok,
      request_id: response.request_id,
      operation: manualControl.operation ?? null,
      run_id: run.id ?? controlState.run_id ?? null,
      run_status: run.status ?? controlState.run_status ?? null,
      queue_status: controlState.queue_status ?? null,
      paused: controlState.paused ?? null,
      terminal: controlState.terminal ?? null,
      latest_manual_transition_type: controlState.latest_manual_transition_type ?? null,
      latest_resume_mode: controlState.latest_resume_mode ?? null,
      raw_response: response,
    },
  },
];

const response = $input.first().json;
const manualControl = response.data?.manual_control ?? {};
const controlState = manualControl.control_state ?? {};
const run = manualControl.run?.run ?? {};

return [
  {
    json: {
      action: 'force_stop',
      ok: response.ok,
      request_id: response.request_id,
      operation: manualControl.operation ?? null,
      run_id: run.id ?? controlState.run_id ?? null,
      run_status: run.status ?? controlState.run_status ?? null,
      queue_status: controlState.queue_status ?? null,
      paused: controlState.paused ?? null,
      terminal: controlState.terminal ?? null,
      latest_manual_transition_type: controlState.latest_manual_transition_type ?? null,
      latest_resume_mode: controlState.latest_resume_mode ?? null,
      raw_response: response,
    },
  },
];
